conversations.value:
Many developers add basic logging that only captures successful events, missing critical security-relevant information needed to detect attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET);

    // Only logs successful logins
    console.log(`User ${username} logged in`);

    res.json({ token });
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});
```

**Attack Scenario**:
```text
Attacker performs credential stuffing attack:
- 10,000 failed login attempts over 2 hours
- Uses rotating IP addresses
- No alerts triggered because failures aren't logged
- Eventually succeeds with compromised credentials
- Attack goes undetected for weeks
```

**Why This Is Dangerous**:
- Failed login attempts are not logged, hiding brute force attacks
- No IP address or user agent captured for forensics
- No timestamp or correlation ID for investigation
- Cannot detect account enumeration attacks
- Impossible to identify compromised accounts after breach

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Structured security logger
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'auth-service' },
  transports: [
    new winston.transports.File({ filename: 'security-events.log' }),
    new winston.transports.Console()
  ]
});

function getClientInfo(req) {
  return {
    ip: req.ip || req.connection.remoteAddress,
    userAgent: req.get('User-Agent'),
    forwardedFor: req.get('X-Forwarded-For'),
    correlationId: req.headers['x-correlation-id'] || uuidv4()
  };
}

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const clientInfo = getClientInfo(req);
  const eventId = uuidv4();

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      // Log failed login - unknown user
      securityLogger.warn('Authentication failed - unknown user', {
        eventType: 'AUTH_FAILURE',
        eventId,
        reason: 'USER_NOT_FOUND',
        attemptedUsername: username,
        ...clientInfo
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      // Log failed login - wrong password
      securityLogger.warn('Authentication failed - invalid password', {
        eventType: 'AUTH_FAILURE',
        eventId,
        reason: 'INVALID_PASSWORD',
        userId: user.id,
        username: user.username,
        ...clientInfo
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET);

    // Log successful login
    securityLogger.info('Authentication successful', {
      eventType: 'AUTH_SUCCESS',
      eventId,
      userId: user.id,
      username: user.username,
      ...clientInfo
    });

    res.json({ token });
  } catch (error) {
    securityLogger.error('Authentication error', {
      eventType: 'AUTH_ERROR',
      eventId,
      error: error.message,
      ...clientInfo
    });
    res.status(500).json({ error: 'Server error' });
  }
});
```

**Key Security Controls**:
- **Structured logging**: JSON format enables automated analysis and alerting
- **All outcomes logged**: Success, failure (user not found), failure (wrong password), and errors
- **Client forensics**: IP address, user agent, and forwarded headers captured
- **Correlation IDs**: Enable tracing requests across distributed systems
- **Separate failure reasons internally**: Helps detect enumeration vs brute force attacks

Comprehensive security logging should cover all security-relevant events across your application, with tamper-proof storage and real-time alerting capabilities.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const WinstonCloudWatch = require('winston-cloudwatch');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Security event types that MUST be logged
const SECURITY_EVENTS = {
  AUTH_SUCCESS: 'Authentication successful',
  AUTH_FAILURE: 'Authentication failed',
  AUTH_LOCKOUT: 'Account locked due to failed attempts',
  SESSION_CREATED: 'New session created',
  SESSION_TERMINATED: 'Session terminated',
  SESSION_HIJACK_ATTEMPT: 'Possible session hijacking detected',
  AUTHZ_SUCCESS: 'Authorization granted',
  AUTHZ_FAILURE: 'Authorization denied',
  PRIVILEGE_ESCALATION: 'Privilege escalation attempt',
  DATA_ACCESS: 'Sensitive data accessed',
  DATA_EXPORT: 'Data exported from system',
  CONFIG_CHANGE: 'Security configuration changed',
  USER_CREATED: 'New user account created',
  USER_DELETED: 'User account deleted',
  PASSWORD_CHANGED: 'Password changed',
  MFA_ENABLED: 'MFA enabled',
  MFA_DISABLED: 'MFA disabled',
  API_KEY_CREATED: 'API key generated',
  API_KEY_REVOKED: 'API key revoked',
  RATE_LIMIT_EXCEEDED: 'Rate limit exceeded',
  INPUT_VALIDATION_FAILURE: 'Input validation failed',
  CSRF_VIOLATION: 'CSRF token mismatch',
  SQL_INJECTION_ATTEMPT: 'Potential SQL injection detected',
  XSS_ATTEMPT: 'Potential XSS attack detected'
};

class SecurityLogger {
  constructor() {
    this.hmacKey = process.env.LOG_INTEGRITY_KEY;

    this.logger = winston.createLogger({
      level: 'info',
      format: winston.format.combine(
        winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
        winston.format.json()
      ),
      defaultMeta: {
        service: process.env.SERVICE_NAME,
        environment: process.env.NODE_ENV,
        version: process.env.APP_VERSION
      },
      transports: [
        // Local file with rotation
        new winston.transports.File({
          filename: 'security-events.log',
          maxsize: 50 * 1024 * 1024, // 50MB
          maxFiles: 30,
          tailable: true
        }),
        // Immutable cloud storage (WORM - Write Once Read Many)
        new WinstonCloudWatch({
          logGroupName: '/security/events',
          logStreamName: `${process.env.SERVICE_NAME}-${process.env.HOSTNAME}`,
          awsRegion: process.env.AWS_REGION,
          retentionInDays: 365
        })
      ]
    });
  }

  // Generate HMAC for log integrity verification
  generateIntegrityHash(logEntry) {
    const data = JSON.stringify(logEntry);
    return crypto
      .createHmac('sha256', this.hmacKey)
      .update(data)
      .digest('hex');
  }

  // Log security event with integrity protection
  logSecurityEvent(eventType, data, severity = 'info') {
    const eventId = uuidv4();
    const timestamp = new Date().toISOString();

    const logEntry = {
      eventId,
      eventType,
      eventDescription: SECURITY_EVENTS[eventType] || eventType,
      timestamp,
      severity: severity.toUpperCase(),
      ...data
    };

    // Add integrity hash to detect tampering
    logEntry.integrityHash = this.generateIntegrityHash(logEntry);

    this.logger[severity](logEntry);

    // Trigger real-time alerts for critical events
    if (severity === 'error' || this.isCriticalEvent(eventType)) {
      this.triggerAlert(logEntry);
    }

    return eventId;
  }

  isCriticalEvent(eventType) {
    const criticalEvents = [
      'AUTH_LOCKOUT',
      'SESSION_HIJACK_ATTEMPT',
      'PRIVILEGE_ESCALATION',
      'SQL_INJECTION_ATTEMPT',
      'XSS_ATTEMPT'
    ];
    return criticalEvents.includes(eventType);
  }

  async triggerAlert(logEntry) {
    // Send to SIEM/alerting system
    try {
      await fetch(process.env.ALERT_WEBHOOK_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          severity: logEntry.severity,
          event: logEntry.eventType,
          details: logEntry,
          timestamp: logEntry.timestamp
        })
      });
    } catch (error) {
      console.error('Failed to send security alert:', error);
    }
  }
}

const securityLogger = new SecurityLogger();

// Middleware to capture request context
function securityContext(req, res, next) {
  req.securityContext = {
    correlationId: req.headers['x-correlation-id'] || uuidv4(),
    clientIp: req.ip || req.connection.remoteAddress,
    userAgent: req.get('User-Agent'),
    forwardedFor: req.get('X-Forwarded-For'),
    referer: req.get('Referer'),
    requestPath: req.path,
    requestMethod: req.method,
    userId: req.user?.id,
    sessionId: req.session?.id
  };
  next();
}

app.use(securityContext);

// Example: Authorization logging middleware
function logAuthorizationCheck(resource, action) {
  return (req, res, next) => {
    const authorized = checkAuthorization(req.user, resource, action);

    if (authorized) {
      securityLogger.logSecurityEvent('AUTHZ_SUCCESS', {
        ...req.securityContext,
        resource,
        action,
        userId: req.user.id
      });
      next();
    } else {
      securityLogger.logSecurityEvent('AUTHZ_FAILURE', {
        ...req.securityContext,
        resource,
        action,
        userId: req.user?.id,
        reason: 'INSUFFICIENT_PERMISSIONS'
      }, 'warn');
      res.status(403).json({ error: 'Access denied' });
    }
  };
}

// Example: Sensitive data access logging
app.get('/api/users/:id/pii', 
  authenticate,
  logAuthorizationCheck('user_pii', 'read'),
  async (req, res) => {
    const userData = await db.getUserPII(req.params.id);

    // Log sensitive data access
    securityLogger.logSecurityEvent('DATA_ACCESS', {
      ...req.securityContext,
      dataType: 'PII',
      targetUserId: req.params.id,
      fieldsAccessed: Object.keys(userData)
    });

    res.json(userData);
  }
);

// Example: Configuration change logging
app.post('/api/admin/settings',
  authenticate,
  requireRole('admin'),
  async (req, res) => {
    const oldSettings = await db.getSettings();
    await db.updateSettings(req.body);

    securityLogger.logSecurityEvent('CONFIG_CHANGE', {
      ...req.securityContext,
      configType: 'security_settings',
      previousValues: oldSettings,
      newValues: req.body,
      changedBy: req.user.id
    }, 'warn');

    res.json({ success: true });
  }
);

module.exports = { app, securityLogger, SECURITY_EVENTS };
```

**Defense in Depth Layers**:

1. **Immutable Log Storage**:
```javascript
// Use AWS CloudWatch Logs with Object Lock or S3 with WORM
const s3Transport = new WinstonS3({
  bucket: 'security-logs-immutable',
  objectLockMode: 'GOVERNANCE',
  objectLockRetainUntilDate: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000)
});
```

2. **Log Integrity Verification**:
```javascript
// Verify log entry hasn't been tampered with
function verifyLogIntegrity(logEntry, storedHash) {
  const { integrityHash, ...data } = logEntry;
  const computedHash = crypto
    .createHmac('sha256', process.env.LOG_INTEGRITY_KEY)
    .update(JSON.stringify(data))
    .digest('hex');
  return computedHash === storedHash;
}
```

3. **Real-time Anomaly Detection**:
```javascript
// Track and alert on anomalous patterns
class SecurityAnomalyDetector {
  constructor() {
    this.failedLogins = new Map();
    this.THRESHOLD = 5;
    this.WINDOW_MS = 15 * 60 * 1000; // 15 minutes
  }

  trackFailedLogin(userId, clientIp) {
    const key = `${userId}:${clientIp}`;
    const attempts = this.failedLogins.get(key) || [];
    const now = Date.now();

    // Remove old attempts
    const recentAttempts = attempts.filter(t => now - t < this.WINDOW_MS);
    recentAttempts.push(now);
    this.failedLogins.set(key, recentAttempts);

    if (recentAttempts.length >= this.THRESHOLD) {
      return { anomalyDetected: true, attemptCount: recentAttempts.length };
    }
    return { anomalyDetected: false, attemptCount: recentAttempts.length };
  }
}
```

**Additional Protections**:
- **Log all security-relevant events**: Authentication, authorization, data access, configuration changes, and attack indicators
- **Include sufficient context**: Who, what, when, where, and outcome for every security event
- **Centralized logging**: Ship logs to SIEM (Splunk, Elastic, etc.) for correlation and analysis
- **Retention policies**: Maintain logs for compliance (typically 1-7 years depending on regulations)
- **Access control on logs**: Restrict who can read/modify log files with separate audit logging
- **Encryption in transit and at rest**: TLS for log shipping, encrypted storage

Your approach is dangerous because without proper security event logging, you cannot detect attacks in progress, investigate incidents after they occur, or meet compliance requirements. The 2024 Change Healthcare attack succeeded partly because attackers operated undetected for 9 days due to logging gaps.

**VULNERABLE CODE**:

```java
import java.sql.*;
import javax.servlet.http.*;
import org.springframework.web.bind.annotation.*;

@RestController
public class AuthController {

    private static final String DB_URL = "jdbc:postgresql://localhost/authdb";
    private static final String DB_USER = "authservice";
    private static final String DB_PASS = System.getenv("DB_PASSWORD");

    @PostMapping("/api/login")
    public ResponseEntity<String> login(@RequestBody LoginRequest request) {
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash, account_locked FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, request.getUsername());
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                boolean locked = rs.getBoolean("account_locked");

                if (locked) {
                    return ResponseEntity.status(403).body("Account locked");
                }

                if (BCrypt.checkpw(request.getPassword(), storedHash)) {
                    String token = generateJWT(request.getUsername());
                    return ResponseEntity.ok(token);
                }
            }
            return ResponseEntity.status(401).body("Invalid credentials");
        } catch (SQLException e) {
            return ResponseEntity.status(500).body("Server error");
        }
    }

    private String generateJWT(String username) {
        // JWT generation logic
        return "token";
    }
}
```

**Attack Scenario**:
```text
Attacker performs credential stuffing with 10,000 leaked credentials:
- No record of failed login attempts
- No detection of unusual login patterns
- No alert when account lockouts occur
- No way to trace which accounts were targeted
- Successful breach goes unnoticed for weeks
```

**Why This Is Dangerous**:
- No logging of authentication failures enables undetected brute force attacks
- No logging of successful logins makes account takeover investigation impossible
- No logging of account lockouts hides targeted attacks against specific users
- Compliance violations (HIPAA, PCI-DSS, SOC2 require security event logging)
- No forensic evidence available after a breach

**SECURE VERSION**:

```java
import java.sql.*;
import java.time.Instant;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.web.bind.annotation.*;

@RestController
public class AuthController {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final Logger appLogger = LoggerFactory.getLogger(AuthController.class);

    private static final String DB_URL = "jdbc:postgresql://localhost/authdb";
    private static final String DB_USER = "authservice";
    private static final String DB_PASS = System.getenv("DB_PASSWORD");

    @PostMapping("/api/login")
    public ResponseEntity<String> login(
            @RequestBody LoginRequest request,
            HttpServletRequest httpRequest) {

        String clientIp = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        String requestId = java.util.UUID.randomUUID().toString();

        // Set MDC context for all log messages in this request
        MDC.put("requestId", requestId);
        MDC.put("clientIp", clientIp);
        MDC.put("username", request.getUsername());

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT user_id, password_hash, account_locked, failed_attempts FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, request.getUsername());
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                long userId = rs.getLong("user_id");
                String storedHash = rs.getString("password_hash");
                boolean locked = rs.getBoolean("account_locked");
                int failedAttempts = rs.getInt("failed_attempts");

                if (locked) {
                    securityLogger.warn(
                        "event=LOGIN_ATTEMPT_LOCKED_ACCOUNT user_id={} username={} ip={} user_agent={}",
                        userId, request.getUsername(), clientIp, userAgent
                    );
                    return ResponseEntity.status(403).body("Account locked");
                }

                if (BCrypt.checkpw(request.getPassword(), storedHash)) {
                    // Log successful authentication
                    securityLogger.info(
                        "event=LOGIN_SUCCESS user_id={} username={} ip={} user_agent={} previous_failures={}",
                        userId, request.getUsername(), clientIp, userAgent, failedAttempts
                    );

                    // Reset failed attempts counter
                    resetFailedAttempts(conn, userId);

                    String token = generateJWT(request.getUsername(), userId);
                    return ResponseEntity.ok(token);
                } else {
                    // Log failed authentication with specific reason
                    int newFailedCount = incrementFailedAttempts(conn, userId);
                    securityLogger.warn(
                        "event=LOGIN_FAILURE reason=INVALID_PASSWORD user_id={} username={} ip={} user_agent={} failed_attempts={}",
                        userId, request.getUsername(), clientIp, userAgent, newFailedCount
                    );

                    if (newFailedCount >= 5) {
                        lockAccount(conn, userId);
                        securityLogger.error(
                            "event=ACCOUNT_LOCKED reason=EXCESSIVE_FAILURES user_id={} username={} ip={} failed_attempts={}",
                            userId, request.getUsername(), clientIp, newFailedCount
                        );
                    }
                }
            } else {
                // Log attempt against non-existent user (potential enumeration)
                securityLogger.warn(
                    "event=LOGIN_FAILURE reason=USER_NOT_FOUND username={} ip={} user_agent={}",
                    request.getUsername(), clientIp, userAgent
                );
            }

            return ResponseEntity.status(401).body("Invalid credentials");
        } catch (SQLException e) {
            appLogger.error("Database error during authentication", e);
            securityLogger.error(
                "event=AUTH_ERROR error_type=DATABASE username={} ip={}",
                request.getUsername(), clientIp
            );
            return ResponseEntity.status(500).body("Server error");
        } finally {
            MDC.clear();
        }
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private int incrementFailedAttempts(Connection conn, long userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = failed_attempts + 1, last_failed_attempt = ? WHERE user_id = ? RETURNING failed_attempts";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setTimestamp(1, Timestamp.from(Instant.now()));
        stmt.setLong(2, userId);
        ResultSet rs = stmt.executeQuery();
        return rs.next() ? rs.getInt(1) : 0;
    }

    private void resetFailedAttempts(Connection conn, long userId) throws SQLException {
        String sql = "UPDATE users SET failed_attempts = 0 WHERE user_id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        stmt.executeUpdate();
    }

    private void lockAccount(Connection conn, long userId) throws SQLException {
        String sql = "UPDATE users SET account_locked = true, locked_at = ? WHERE user_id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setTimestamp(1, Timestamp.from(Instant.now()));
        stmt.setLong(2, userId);
        stmt.executeUpdate();
    }

    private String generateJWT(String username, long userId) {
        // JWT generation with user context
        return "token";
    }
}
```

**Key Security Controls**:
- **Structured security logging**: Uses dedicated SECURITY_AUDIT logger with consistent event format for SIEM integration
- **Complete event coverage**: Logs all authentication outcomes (success, failure, lockout) with context
- **Request correlation**: MDC provides request ID for tracing across distributed systems
- **Sensitive data handling**: Logs username and IP but never passwords or tokens

A comprehensive security logging strategy must cover all security-relevant events across your application. The 2024 Change Healthcare breach demonstrated that attackers exploit logging gaps - they operated undetected because privilege escalation, lateral movement, and data access weren't properly logged.

**PRODUCTION PATTERN**:

```java
import java.time.Instant;
import java.util.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.stereotype.Component;
import org.springframework.web.bind.annotation.*;
import com.fasterxml.jackson.databind.ObjectMapper;

// Security Event Types Enum
public enum SecurityEventType {
    // Authentication Events
    LOGIN_SUCCESS, LOGIN_FAILURE, LOGOUT, SESSION_CREATED, SESSION_DESTROYED,
    PASSWORD_CHANGE, PASSWORD_RESET_REQUEST, MFA_SUCCESS, MFA_FAILURE,

    // Authorization Events  
    ACCESS_GRANTED, ACCESS_DENIED, PRIVILEGE_ESCALATION, ROLE_CHANGE,

    // Data Access Events
    SENSITIVE_DATA_ACCESS, BULK_DATA_EXPORT, PII_ACCESSED, PHI_ACCESSED,

    // Administrative Events
    USER_CREATED, USER_DELETED, USER_MODIFIED, CONFIG_CHANGE,
    PERMISSION_GRANTED, PERMISSION_REVOKED,

    // Security Threats
    BRUTE_FORCE_DETECTED, INJECTION_ATTEMPT, SUSPICIOUS_ACTIVITY,
    RATE_LIMIT_EXCEEDED, IP_BLOCKED, ACCOUNT_LOCKED,

    // System Events
    APPLICATION_START, APPLICATION_STOP, SECURITY_SCAN_COMPLETE
}

// Immutable Security Event Record
public record SecurityEvent(
    String eventId,
    SecurityEventType eventType,
    Instant timestamp,
    String userId,
    String username,
    String clientIp,
    String userAgent,
    String requestId,
    String sessionId,
    String resourceType,
    String resourceId,
    String action,
    String outcome,
    Map<String, Object> additionalContext,
    String severity
) {
    public SecurityEvent {
        // Validate required fields
        Objects.requireNonNull(eventId, "eventId required");
        Objects.requireNonNull(eventType, "eventType required");
        Objects.requireNonNull(timestamp, "timestamp required");
        Objects.requireNonNull(outcome, "outcome required");

        // Ensure additionalContext is immutable
        additionalContext = additionalContext != null 
            ? Map.copyOf(additionalContext) 
            : Map.of();
    }
}

// Central Security Audit Logger Service
@Component
public class SecurityAuditLogger {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final Logger alertLogger = LoggerFactory.getLogger("SECURITY_ALERTS");
    private static final ObjectMapper objectMapper = new ObjectMapper();

    // Also write to database for long-term storage and querying
    private final SecurityEventRepository eventRepository;
    private final AlertingService alertingService;
    private final MetricsService metricsService;

    public SecurityAuditLogger(
            SecurityEventRepository eventRepository,
            AlertingService alertingService,
            MetricsService metricsService) {
        this.eventRepository = eventRepository;
        this.alertingService = alertingService;
        this.metricsService = metricsService;
    }

    public void logSecurityEvent(SecurityEvent event) {
        // 1. Structured JSON logging for SIEM ingestion
        try {
            String jsonEvent = objectMapper.writeValueAsString(event);
            securityLogger.info(jsonEvent);
        } catch (Exception e) {
            securityLogger.error(
                "event=LOG_SERIALIZATION_ERROR eventType={} eventId={}",
                event.eventType(), event.eventId()
            );
        }

        // 2. Persist to database for compliance and investigation
        try {
            eventRepository.save(event);
        } catch (Exception e) {
            // Critical: If we can't persist security events, alert immediately
            alertLogger.error(
                "CRITICAL: Security event persistence failed - eventId={} eventType={}",
                event.eventId(), event.eventType()
            );
            alertingService.sendCriticalAlert(
                "Security Logging Failure",
                "Unable to persist security events to database"
            );
        }

        // 3. Update metrics for dashboards
        metricsService.incrementSecurityEventCounter(
            event.eventType().name(),
            event.outcome()
        );

        // 4. Trigger real-time alerts for critical events
        if (requiresImmediateAlert(event)) {
            triggerSecurityAlert(event);
        }
    }

    private boolean requiresImmediateAlert(SecurityEvent event) {
        return switch (event.eventType()) {
            case PRIVILEGE_ESCALATION,
                 BRUTE_FORCE_DETECTED,
                 INJECTION_ATTEMPT,
                 BULK_DATA_EXPORT -> true;
            case ACCESS_DENIED -> "CRITICAL".equals(event.severity());
            case LOGIN_FAILURE -> {
                // Alert on excessive failures from same IP
                int recentFailures = getRecentFailureCount(event.clientIp());
                yield recentFailures >= 10;
            }
            default -> false;
        };
    }

    private void triggerSecurityAlert(SecurityEvent event) {
        alertLogger.error(
            "SECURITY_ALERT eventType={} userId={} ip={} resource={} details={}",
            event.eventType(),
            event.userId(),
            event.clientIp(),
            event.resourceId(),
            event.additionalContext()
        );

        alertingService.sendSecurityAlert(
            event.eventType().name(),
            buildAlertMessage(event),
            determineSeverity(event)
        );
    }

    private int getRecentFailureCount(String clientIp) {
        return eventRepository.countRecentEventsByIp(
            clientIp,
            SecurityEventType.LOGIN_FAILURE,
            Instant.now().minusSeconds(300)
        );
    }

    private String buildAlertMessage(SecurityEvent event) {
        return String.format(
            "Security Event: %s | User: %s | IP: %s | Resource: %s",
            event.eventType(), event.userId(), event.clientIp(), event.resourceId()
        );
    }

    private AlertSeverity determineSeverity(SecurityEvent event) {
        return switch (event.eventType()) {
            case PRIVILEGE_ESCALATION, INJECTION_ATTEMPT, BULK_DATA_EXPORT -> AlertSeverity.CRITICAL;
            case BRUTE_FORCE_DETECTED, ACCOUNT_LOCKED -> AlertSeverity.HIGH;
            case ACCESS_DENIED, SUSPICIOUS_ACTIVITY -> AlertSeverity.MEDIUM;
            default -> AlertSeverity.LOW;
        };
    }
}

