package security

import (
    "context"
    "encoding/json"
    "sync"
    "time"

    "github.com/google/uuid"
    "go.uber.org/zap"
    "go.uber.org/zap/zapcore"
)

// SecurityEventType defines categories of security events
type SecurityEventType string

const (
    EventAuthentication     SecurityEventType = "authentication"
    EventAuthorization      SecurityEventType = "authorization"
    EventDataAccess         SecurityEventType = "data_access"
    EventAdminAction        SecurityEventType = "admin_action"
    EventConfigChange       SecurityEventType = "config_change"
    EventPrivilegeEscalation SecurityEventType = "privilege_escalation"
    EventSessionManagement  SecurityEventType = "session_management"
    EventRateLimitExceeded  SecurityEventType = "rate_limit_exceeded"
    EventInputValidation    SecurityEventType = "input_validation_failure"
    EventSecurityScan       SecurityEventType = "security_scan_detected"
)

type SecurityEvent struct {
    EventID       string            `json:"event_id"`
    Timestamp     time.Time         `json:"timestamp"`
    EventType     SecurityEventType `json:"event_type"`
    Severity      string            `json:"severity"` // INFO, WARNING, CRITICAL
    UserID        string            `json:"user_id,omitempty"`
    Username      string            `json:"username,omitempty"`
    SessionID     string            `json:"session_id,omitempty"`
    IPAddress     string            `json:"ip_address"`
    UserAgent     string            `json:"user_agent"`
    Action        string            `json:"action"`
    Resource      string            `json:"resource,omitempty"`
    ResourceID    string            `json:"resource_id,omitempty"`
    Success       bool              `json:"success"`
    FailReason    string            `json:"fail_reason,omitempty"`
    RequestID     string            `json:"request_id"`
    ServiceName   string            `json:"service_name"`
    Environment   string            `json:"environment"`
    Metadata      map[string]string `json:"metadata,omitempty"`
}

type SecurityLogger struct {
    logger      *zap.Logger
    eventChan   chan SecurityEvent
    wg          sync.WaitGroup
    serviceName string
    environment string
    bufferSize  int
    flushTicker *time.Ticker
    done        chan struct{}
}

func NewSecurityLogger(serviceName, environment string, bufferSize int) (*SecurityLogger, error) {
    config := zap.Config{
        Level:       zap.NewAtomicLevelAt(zapcore.InfoLevel),
        Development: environment != "production",
        Encoding:    "json",
        EncoderConfig: zapcore.EncoderConfig{
            TimeKey:        "timestamp",
            LevelKey:       "level",
            NameKey:        "logger",
            MessageKey:     "message",
            StacktraceKey:  "stacktrace",
            EncodeLevel:    zapcore.LowercaseLevelEncoder,
            EncodeTime:     zapcore.ISO8601TimeEncoder,
            EncodeDuration: zapcore.SecondsDurationEncoder,
        },
        OutputPaths:      []string{"stdout", "/var/log/security/events.json"},
        ErrorOutputPaths: []string{"stderr"},
    }

    logger, err := config.Build()
    if err != nil {
        return nil, err
    }

    sl := &SecurityLogger{
        logger:      logger,
        eventChan:   make(chan SecurityEvent, bufferSize),
        serviceName: serviceName,
        environment: environment,
        bufferSize:  bufferSize,
        flushTicker: time.NewTicker(5 * time.Second),
        done:        make(chan struct{}),
    }

    // Start async workers
    for i := 0; i < 3; i++ {
        sl.wg.Add(1)
        go sl.processEvents()
    }

    return sl, nil
}

func (sl *SecurityLogger) processEvents() {
    defer sl.wg.Done()
    for {
        select {
        case event := <-sl.eventChan:
            sl.writeEvent(event)
        case <-sl.done:
            // Drain remaining events
            for len(sl.eventChan) > 0 {
                event := <-sl.eventChan
                sl.writeEvent(event)
            }
            return
        }
    }
}

func (sl *SecurityLogger) writeEvent(event SecurityEvent) {
    fields := []zap.Field{
        zap.String("event_id", event.EventID),
        zap.Time("event_timestamp", event.Timestamp),
        zap.String("event_type", string(event.EventType)),
        zap.String("severity", event.Severity),
        zap.String("ip_address", event.IPAddress),
        zap.String("action", event.Action),
        zap.Bool("success", event.Success),
        zap.String("request_id", event.RequestID),
        zap.String("service_name", event.ServiceName),
        zap.String("environment", event.Environment),
    }

    if event.UserID != "" {
        fields = append(fields, zap.String("user_id", event.UserID))
    }
    if event.Username != "" {
        fields = append(fields, zap.String("username", event.Username))
    }
    if event.SessionID != "" {
        fields = append(fields, zap.String("session_id", event.SessionID))
    }
    if event.Resource != "" {
        fields = append(fields, zap.String("resource", event.Resource))
    }
    if event.FailReason != "" {
        fields = append(fields, zap.String("fail_reason", event.FailReason))
    }
    if len(event.Metadata) > 0 {
        fields = append(fields, zap.Any("metadata", event.Metadata))
    }

    switch event.Severity {
    case "CRITICAL":
        sl.logger.Error("security_event", fields...)
    case "WARNING":
        sl.logger.Warn("security_event", fields...)
    default:
        sl.logger.Info("security_event", fields...)
    }
}

// LogEvent queues a security event for async processing
func (sl *SecurityLogger) LogEvent(event SecurityEvent) {
    event.EventID = uuid.New().String()
    event.Timestamp = time.Now().UTC()
    event.ServiceName = sl.serviceName
    event.Environment = sl.environment

    select {
    case sl.eventChan <- event:
        // Event queued successfully
    default:
        // Buffer full - log synchronously to prevent data loss
        sl.logger.Warn("security_log_buffer_full",
            zap.String("event_type", string(event.EventType)),
            zap.Int("buffer_size", sl.bufferSize),
        )
        sl.writeEvent(event)
    }
}

