// Threat detection thresholds
const THRESHOLDS = {
  FAILED_LOGINS_PER_USER: 5,
  FAILED_LOGINS_PER_IP: 10,
  FAILED_LOGINS_WINDOW_SECONDS: 300,
  PASSWORD_RESETS_PER_IP: 3,
  PASSWORD_RESETS_WINDOW_SECONDS: 3600,
  CREDENTIAL_STUFFING_THRESHOLD: 50
};

const SecurityEvents = {
  LOGIN_SUCCESS: 'AUTH_LOGIN_SUCCESS',
  LOGIN_FAILURE: 'AUTH_LOGIN_FAILURE',
  ACCOUNT_LOCKED: 'AUTH_ACCOUNT_LOCKED',
  BRUTE_FORCE_DETECTED: 'THREAT_BRUTE_FORCE_DETECTED',
  CREDENTIAL_STUFFING_DETECTED: 'THREAT_CREDENTIAL_STUFFING_DETECTED',
  SUSPICIOUS_IP: 'THREAT_SUSPICIOUS_IP',
  RATE_LIMIT_EXCEEDED: 'SECURITY_RATE_LIMIT_EXCEEDED'
};

class ThreatDetector {
  constructor(redis, logger) {
    this.redis = redis;
    this.logger = logger;
  }

  async trackFailedLogin(username, ip) {
    const userKey = `failed:user:${username}`;
    const ipKey = `failed:ip:${ip}`;
    const globalKey = `failed:global:${this.getTimeWindow()}`;

    const pipeline = this.redis.pipeline();

    // Track per-user failures
    pipeline.incr(userKey);
    pipeline.expire(userKey, THRESHOLDS.FAILED_LOGINS_WINDOW_SECONDS);

    // Track per-IP failures
    pipeline.incr(ipKey);
    pipeline.expire(ipKey, THRESHOLDS.FAILED_LOGINS_WINDOW_SECONDS);

    // Track global failures for credential stuffing detection
    pipeline.incr(globalKey);
    pipeline.expire(globalKey, 60);

    const results = await pipeline.exec();

    const userFailures = results[0][1];
    const ipFailures = results[2][1];
    const globalFailures = results[4][1];

    return { userFailures, ipFailures, globalFailures };
  }

  async detectThreats(metrics, username, ip, req) {
    const threats = [];

    // Detect user-targeted brute force
    if (metrics.userFailures >= THRESHOLDS.FAILED_LOGINS_PER_USER) {
      threats.push({
        type: SecurityEvents.BRUTE_FORCE_DETECTED,
        severity: 'HIGH',
        details: {
          targetUser: username,
          failureCount: metrics.userFailures,
          windowSeconds: THRESHOLDS.FAILED_LOGINS_WINDOW_SECONDS
        }
      });

      // Auto-lock account
      await this.lockAccount(username, '30m');
    }

    // Detect IP-based attack
    if (metrics.ipFailures >= THRESHOLDS.FAILED_LOGINS_PER_IP) {
      threats.push({
        type: SecurityEvents.SUSPICIOUS_IP,
        severity: 'HIGH',
        details: {
          sourceIp: ip,
          failureCount: metrics.ipFailures,
          windowSeconds: THRESHOLDS.FAILED_LOGINS_WINDOW_SECONDS
        }
      });

      // Add IP to temporary blocklist
      await this.blockIp(ip, '1h');
    }

    // Detect credential stuffing (high volume distributed attack)
    if (metrics.globalFailures >= THRESHOLDS.CREDENTIAL_STUFFING_THRESHOLD) {
      threats.push({
        type: SecurityEvents.CREDENTIAL_STUFFING_DETECTED,
        severity: 'CRITICAL',
        details: {
          failuresPerMinute: metrics.globalFailures,
          detectedAt: new Date().toISOString()
        }
      });

      // Alert security team immediately
      await this.sendCriticalAlert('Credential stuffing attack detected', {
        failuresPerMinute: metrics.globalFailures
      });
    }

    // Log all detected threats
    for (const threat of threats) {
      this.logger.warn({
        eventId: uuidv4(),
        eventType: threat.type,
        severity: threat.severity,
        sourceIp: ip,
        userAgent: req.get('User-Agent'),
        ...threat.details
      });
    }

    return threats;
  }

  async lockAccount(username, duration) {
    await this.redis.set(
      `locked:${username}`,
      JSON.stringify({ lockedAt: new Date().toISOString(), reason: 'BRUTE_FORCE' }),
      'EX',
      this.parseDuration(duration)
    );

    this.logger.warn({
      eventId: uuidv4(),
      eventType: SecurityEvents.ACCOUNT_LOCKED,
      username,
      duration,
      reason: 'Excessive failed login attempts'
    });
  }

  async blockIp(ip, duration) {
    await this.redis.set(
      `blocked:ip:${ip}`,
      JSON.stringify({ blockedAt: new Date().toISOString() }),
      'EX',
      this.parseDuration(duration)
    );
  }

  async isAccountLocked(username) {
    return await this.redis.exists(`locked:${username}`);
  }

  async isIpBlocked(ip) {
    return await this.redis.exists(`blocked:ip:${ip}`);
  }

  async sendCriticalAlert(message, details) {
    // Integration with PagerDuty/Slack/etc.
    this.logger.error({
      eventId: uuidv4(),
      eventType: 'ALERT_CRITICAL',
      message,
      ...details,
      alertSentAt: new Date().toISOString()
    });

    // Webhook to security operations
    // await fetch(process.env.SECURITY_WEBHOOK_URL, {...});
  }

  getTimeWindow() {
    return Math.floor(Date.now() / 60000);
  }

  parseDuration(duration) {
    const match = duration.match(/^(\d+)(s|m|h|d)$/);
    if (!match) return 300;
    const [, value, unit] = match;
    const multipliers = { s: 1, m: 60, h: 3600, d: 86400 };
    return parseInt(value) * multipliers[unit];
  }
}

const threatDetector = new ThreatDetector(redis, securityLogger);

// Middleware to check IP blocklist
async function checkBlocklist(req, res, next) {
  const clientIp = req.ip || req.connection.remoteAddress;

  if (await threatDetector.isIpBlocked(clientIp)) {
    securityLogger.warn({
      eventId: uuidv4(),
      eventType: 'BLOCKED_REQUEST',
      sourceIp: clientIp,
      path: req.path
    });
    return res.status(429).json({ error: 'Too many requests' });
  }
  next();
}

app.use(checkBlocklist);

app.post('/api/login', async (req, res) => {
  const startTime = Date.now();
  const eventId = uuidv4();
  const clientIp = req.ip || req.connection.remoteAddress;
  const { username, password } = req.body;

  try {
    // Check if account is locked
    if (await threatDetector.isAccountLocked(username)) {
      securityLogger.info({
        eventId,
        eventType: 'AUTH_BLOCKED_LOCKED_ACCOUNT',
        username,
        sourceIp: clientIp
      });
      return res.status(423).json({ error: 'Account temporarily locked' });
    }

    const user = users.get(username);

    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      // Track and analyze failed attempt
      const metrics = await threatDetector.trackFailedLogin(username, clientIp);
      await threatDetector.detectThreats(metrics, username, clientIp, req);

      securityLogger.info({
        eventId,
        eventType: SecurityEvents.LOGIN_FAILURE,
        username,
        sourceIp: clientIp,
        userAgent: req.get('User-Agent'),
        reason: !user ? 'USER_NOT_FOUND' : 'INVALID_PASSWORD',
        duration: Date.now() - startTime
      });

      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Successful login
    const token = jwt.sign(
      { userId: user.id, username },
      process.env.JWT_SECRET,
      { expiresIn: '1h' }
    );

    // Clear failed attempts on success
    await redis.del(`failed:user:${username}`);

    securityLogger.info({
      eventId,
      eventType: SecurityEvents.LOGIN_SUCCESS,
      username,
      userId: user.id,
      sourceIp: clientIp,
      userAgent: req.get('User-Agent'),
      duration: Date.now() - startTime
    });

    res.json({ token });

  } catch (error) {
    securityLogger.error({
      eventId,
      eventType: 'AUTH_ERROR',
      error: error.message,
      stack: error.stack,
      sourceIp: clientIp
    });
    res.status(500).json({ error: 'Authentication service unavailable' });
  }
});

