**PRODUCTION PATTERN**:

```java
import java.time.Instant;
import java.util.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import com.fasterxml.jackson.databind.ObjectMapper;

public class SecurityAuditLogger {
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final ObjectMapper objectMapper = new ObjectMapper();

    public enum SecurityEventType {
        // Authentication events
        LOGIN_SUCCESS, LOGIN_FAILURE, LOGOUT, SESSION_CREATED, SESSION_DESTROYED,
        MFA_SUCCESS, MFA_FAILURE, PASSWORD_CHANGE, PASSWORD_RESET_REQUEST,

        // Authorization events
        ACCESS_GRANTED, ACCESS_DENIED, PRIVILEGE_ESCALATION, ROLE_CHANGE,

        // Data access events
        DATA_READ, DATA_CREATE, DATA_UPDATE, DATA_DELETE, DATA_EXPORT,
        SENSITIVE_DATA_ACCESS, PII_ACCESS,

        // Administrative events
        USER_CREATED, USER_DELETED, USER_MODIFIED, PERMISSION_GRANTED,
        PERMISSION_REVOKED, CONFIG_CHANGE, SYSTEM_SETTING_MODIFIED,

        // Security anomalies
        BRUTE_FORCE_DETECTED, RATE_LIMIT_EXCEEDED, SUSPICIOUS_ACTIVITY,
        INPUT_VALIDATION_FAILURE, INJECTION_ATTEMPT_BLOCKED
    }

    public static class SecurityEvent {
        public String eventId;
        public SecurityEventType eventType;
        public String timestamp;
        public String severity;
        public String actorUserId;
        public String actorUsername;
        public String actorIp;
        public String actorUserAgent;
        public String targetResource;
        public String targetUserId;
        public String action;
        public String outcome;
        public Map<String, Object> details;
        public String sessionId;
        public String correlationId;

        public SecurityEvent(SecurityEventType type) {
            this.eventId = UUID.randomUUID().toString();
            this.eventType = type;
            this.timestamp = Instant.now().toString();
            this.details = new HashMap<>();
        }
    }

    public static class SecurityEventBuilder {
        private final SecurityEvent event;

        public SecurityEventBuilder(SecurityEventType type) {
            this.event = new SecurityEvent(type);
        }

        public SecurityEventBuilder withActor(String userId, String username) {
            event.actorUserId = userId;
            event.actorUsername = username;
            return this;
        }

        public SecurityEventBuilder withRequest(HttpServletRequest request) {
            event.actorIp = extractClientIp(request);
            event.actorUserAgent = request.getHeader("User-Agent");
            event.sessionId = request.getSession(false) != null ? 
                request.getSession().getId() : "no-session";
            event.correlationId = request.getHeader("X-Correlation-ID");
            return this;
        }

        public SecurityEventBuilder withTarget(String resource, String targetUserId) {
            event.targetResource = resource;
            event.targetUserId = targetUserId;
            return this;
        }

        public SecurityEventBuilder withOutcome(String outcome, String severity) {
            event.outcome = outcome;
            event.severity = severity;
            return this;
        }

        public SecurityEventBuilder withDetail(String key, Object value) {
            event.details.put(key, value);
            return this;
        }

        public SecurityEventBuilder withAction(String action) {
            event.action = action;
            return this;
        }

        public void log() {
            try {
                String json = objectMapper.writeValueAsString(event);

                switch (event.severity) {
                    case "CRITICAL":
                    case "HIGH":
                        securityLogger.error(json);
                        break;
                    case "MEDIUM":
                        securityLogger.warn(json);
                        break;
                    default:
                        securityLogger.info(json);
                }
            } catch (Exception e) {
                securityLogger.error("LOGGING_FAILURE: Unable to serialize security event | eventType={} | error={}",
                    event.eventType, e.getMessage());
            }
        }

        private String extractClientIp(HttpServletRequest request) {
            String[] headerNames = {"X-Forwarded-For", "X-Real-IP", "Proxy-Client-IP"};
            for (String header : headerNames) {
                String ip = request.getHeader(header);
                if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
                    return ip.split(",")[0].trim();
                }
            }
            return request.getRemoteAddr();
        }
    }

    // Convenience factory methods
    public static SecurityEventBuilder authenticationEvent(SecurityEventType type) {
        return new SecurityEventBuilder(type);
    }

    public static SecurityEventBuilder dataAccessEvent(SecurityEventType type) {
        return new SecurityEventBuilder(type);
    }

    public static SecurityEventBuilder adminEvent(SecurityEventType type) {
        return new SecurityEventBuilder(type);
    }
}
```

