    public void promoteToAdmin(HttpServletRequest request, String currentUserId, 
                               String targetUserId) throws SecurityException {

        // Log privilege escalation attempt
        SecurityAuditLogger.authenticationEvent(SecurityAuditLogger.SecurityEventType.PRIVILEGE_ESCALATION)
            .withActor(currentUserId, getCurrentUsername(currentUserId))
            .withRequest(request)
            .withTarget("user.role", targetUserId)
            .withAction("PROMOTE_TO_ADMIN")
            .withDetail("previousRole", getUserRole(targetUserId))
            .withDetail("newRole", "ADMIN")
            .withOutcome("ATTEMPTED", "HIGH")
            .log();

        // Verify authorization
        if (!isAuthorizedForAdminPromotion(currentUserId)) {
            SecurityAuditLogger.authenticationEvent(SecurityAuditLogger.SecurityEventType.ACCESS_DENIED)
                .withActor(currentUserId, getCurrentUsername(currentUserId))
                .withRequest(request)
                .withTarget("user.role", targetUserId)
                .withAction("PROMOTE_TO_ADMIN")
                .withOutcome("DENIED", "HIGH")
                .withDetail("reason", "Insufficient privileges")
                .log();
            throw new SecurityException("Unauthorized admin promotion attempt");
        }

        // Perform promotion
        try {
            updateUserRole(targetUserId, "ADMIN");

            SecurityAuditLogger.adminEvent(SecurityAuditLogger.SecurityEventType.ROLE_CHANGE)
                .withActor(currentUserId, getCurrentUsername(currentUserId))
                .withRequest(request)
                .withTarget("user.role", targetUserId)
                .withAction("PROMOTE_TO_ADMIN")
                .withOutcome("SUCCESS", "HIGH")
                .withDetail("targetUsername", getUsernameById(targetUserId))
                .log();

        } catch (Exception e) {
            SecurityAuditLogger.adminEvent(SecurityAuditLogger.SecurityEventType.ROLE_CHANGE)
                .withActor(currentUserId, getCurrentUsername(currentUserId))
                .withRequest(request)
                .withTarget("user.role", targetUserId)
                .withAction("PROMOTE_TO_ADMIN")
                .withOutcome("FAILED", "MEDIUM")
                .withDetail("error", e.getMessage())
                .log();
            throw e;
        }
    }

