// Hash chain for log integrity
public class AuditIntegrity {
    private static String previousHash = "GENESIS";

    public static synchronized String addIntegrityHash(SecurityEvent event) {
        String content = event.eventId + event.timestamp + previousHash;
        String hash = DigestUtils.sha256Hex(content);
        event.details.put("integrityHash", hash);
        event.details.put("previousHash", previousHash);
        previousHash = hash;
        return hash;
    }
