		// Log failed password - possible brute force
		h.securityLog.LogAuthEvent(ctx, "login_invalid_password", req.Username, false, r, map[string]string{
			"reason": "password_mismatch",
		})
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Log successful authentication
	h.securityLog.LogAuthEvent(ctx, "login_success", req.Username, true, r, map[string]string{
		"user_id": string(rune(userID)),
	})

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "authenticated"})
}

func getClientIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		return xff
	}
	return r.RemoteAddr
}

func getRequestID(ctx context.Context) string {
	if id, ok := ctx.Value("request_id").(string); ok {
		return id
	}
	return "unknown"
}
