import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"sync"
	"time"
)

// SecurityEventType defines categories of security events
type SecurityEventType string

const (
	// Authentication Events
	EventLoginSuccess        SecurityEventType = "auth.login.success"
	EventLoginFailure        SecurityEventType = "auth.login.failure"
	EventLogout              SecurityEventType = "auth.logout"
	EventPasswordChange      SecurityEventType = "auth.password.change"
	EventPasswordReset       SecurityEventType = "auth.password.reset"
	EventMFAChallenge        SecurityEventType = "auth.mfa.challenge"
	EventMFAFailure          SecurityEventType = "auth.mfa.failure"
	EventSessionCreated      SecurityEventType = "auth.session.created"
	EventSessionExpired      SecurityEventType = "auth.session.expired"
	EventSessionRevoked      SecurityEventType = "auth.session.revoked"

	// Authorization Events
	EventAccessGranted       SecurityEventType = "authz.access.granted"
	EventAccessDenied        SecurityEventType = "authz.access.denied"
	EventPrivilegeEscalation SecurityEventType = "authz.privilege.escalation"
	EventRoleChange          SecurityEventType = "authz.role.change"

	// Data Access Events
	EventSensitiveDataAccess SecurityEventType = "data.sensitive.access"
	EventDataExport          SecurityEventType = "data.export"
	EventBulkOperation       SecurityEventType = "data.bulk.operation"

	// Administrative Events
	EventUserCreated         SecurityEventType = "admin.user.created"
	EventUserDeleted         SecurityEventType = "admin.user.deleted"
	EventConfigChange        SecurityEventType = "admin.config.change"
	EventAPIKeyCreated       SecurityEventType = "admin.apikey.created"
	EventAPIKeyRevoked       SecurityEventType = "admin.apikey.revoked"

	// Security Anomalies
	EventRateLimitExceeded   SecurityEventType = "security.ratelimit.exceeded"
	EventSuspiciousActivity  SecurityEventType = "security.suspicious.activity"
	EventInputValidationFail SecurityEventType = "security.input.validation"
	EventCSRFViolation       SecurityEventType = "security.csrf.violation"
)

// SecurityEvent represents a loggable security event
type SecurityEvent struct {
	ID          string            `json:"event_id"`
	Timestamp   time.Time         `json:"timestamp"`
	EventType   SecurityEventType `json:"event_type"`
	Severity    string            `json:"severity"`
	UserID      string            `json:"user_id,omitempty"`
	Username    string            `json:"username,omitempty"`
	SourceIP    string            `json:"source_ip"`
	UserAgent   string            `json:"user_agent"`
	RequestID   string            `json:"request_id"`
	Resource    string            `json:"resource,omitempty"`
	Action      string            `json:"action,omitempty"`
	Outcome     string            `json:"outcome"`
	Reason      string            `json:"reason,omitempty"`
	Metadata    map[string]string `json:"metadata,omitempty"`
	SessionID   string            `json:"session_id,omitempty"`
	GeoLocation *GeoInfo          `json:"geo,omitempty"`
}

type GeoInfo struct {
	Country string `json:"country"`
	City    string `json:"city"`
}

// AsyncSecurityLogger handles high-volume security logging
type AsyncSecurityLogger struct {
	eventChan    chan SecurityEvent
	batchSize    int
	flushTimeout time.Duration
	wg           sync.WaitGroup
	outputs      []LogOutput
	metrics      *LogMetrics
	shutdown     chan struct{}
}

type LogOutput interface {
	Write(events []SecurityEvent) error
}

type LogMetrics struct {
	mu              sync.Mutex
	EventsLogged    int64
	EventsDropped   int64
	BatchesWritten  int64
	WriteErrors     int64
	AverageLatency  time.Duration
}

func NewAsyncSecurityLogger(bufferSize int, batchSize int, flushTimeout time.Duration, outputs ...LogOutput) *AsyncSecurityLogger {
	logger := &AsyncSecurityLogger{
		eventChan:    make(chan SecurityEvent, bufferSize),
		batchSize:    batchSize,
		flushTimeout: flushTimeout,
		outputs:      outputs,
		metrics:      &LogMetrics{},
		shutdown:     make(chan struct{}),
	}

	logger.wg.Add(1)
	go logger.processEvents()

	return logger
}

func (l *AsyncSecurityLogger) processEvents() {
	defer l.wg.Done()

	batch := make([]SecurityEvent, 0, l.batchSize)
	timer := time.NewTimer(l.flushTimeout)
	defer timer.Stop()

	for {
		select {
		case event := <-l.eventChan:
			batch = append(batch, event)
			if len(batch) >= l.batchSize {
				l.writeBatch(batch)
				batch = batch[:0]
				timer.Reset(l.flushTimeout)
			}

		case <-timer.C:
			if len(batch) > 0 {
				l.writeBatch(batch)
				batch = batch[:0]
			}
			timer.Reset(l.flushTimeout)

		case <-l.shutdown:
			// Drain remaining events
			for {
				select {
				case event := <-l.eventChan:
					batch = append(batch, event)
				default:
					if len(batch) > 0 {
						l.writeBatch(batch)
					}
					return
				}
			}
		}
	}
}

func (l *AsyncSecurityLogger) writeBatch(batch []SecurityEvent) {
	start := time.Now()

	for _, output := range l.outputs {
		if err := output.Write(batch); err != nil {
			l.metrics.mu.Lock()
			l.metrics.WriteErrors++
			l.metrics.mu.Unlock()
			// Fallback to stderr for critical security events
			for _, event := range batch {
				data, _ := json.Marshal(event)
				fmt.Printf("FALLBACK_SECURITY_LOG: %s\n", string(data))
			}
		}
	}

	l.metrics.mu.Lock()
	l.metrics.EventsLogged += int64(len(batch))
	l.metrics.BatchesWritten++
	l.metrics.AverageLatency = time.Since(start)
	l.metrics.mu.Unlock()
}

// LogEvent logs a security event asynchronously with backpressure handling
func (l *AsyncSecurityLogger) LogEvent(event SecurityEvent) {
	select {
	case l.eventChan <- event:
		// Event queued successfully
	default:
		// Buffer full - increment dropped counter and log synchronously
		l.metrics.mu.Lock()
		l.metrics.EventsDropped++
		l.metrics.mu.Unlock()

		// Critical events logged synchronously as fallback
		if event.Severity == "critical" || event.Severity == "high" {
			data, _ := json.Marshal(event)
			fmt.Printf("CRITICAL_SECURITY_LOG: %s\n", string(data))
		}
	}
}

func (l *AsyncSecurityLogger) Shutdown() {
	close(l.shutdown)
	l.wg.Wait()
}

// SecurityMiddleware provides automatic security event logging
type SecurityMiddleware struct {
	logger          *AsyncSecurityLogger
	failureThreshold int
	failureWindow    time.Duration
	failureTracker   map[string]*FailureInfo
	mu               sync.RWMutex
}

type FailureInfo struct {
	Count      int
	FirstSeen  time.Time
	LastSeen   time.Time
}

func (m *SecurityMiddleware) TrackFailure(sourceIP string, eventType SecurityEventType) {
	m.mu.Lock()
	defer m.mu.Unlock()

	now := time.Now()
	key := fmt.Sprintf("%s:%s", sourceIP, eventType)

	if info, exists := m.failureTracker[key]; exists {
		if now.Sub(info.FirstSeen) > m.failureWindow {
			// Reset window
			info.Count = 1
			info.FirstSeen = now
		} else {
			info.Count++
		}
		info.LastSeen = now

		// Detect brute force pattern
		if info.Count >= m.failureThreshold {
			m.logger.LogEvent(SecurityEvent{
				ID:        generateEventID(),
				Timestamp: now,
				EventType: EventSuspiciousActivity,
				Severity:  "high",
				SourceIP:  sourceIP,
				Outcome:   "detected",
				Reason:    "brute_force_pattern_detected",
				Metadata: map[string]string{
					"failure_count":   fmt.Sprintf("%d", info.Count),
					"window_seconds":  fmt.Sprintf("%.0f", m.failureWindow.Seconds()),
					"original_event":  string(eventType),
				},
			})
		}
	} else {
		m.failureTracker[key] = &FailureInfo{
			Count:     1,
			FirstSeen: now,
			LastSeen:  now,
		}
	}
}

func generateEventID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

