    latitude: geo.ll?.[0] || null,
    longitude: geo.ll?.[1] || null,
    timestamp: new Date().toISOString(),
    sessionId: req.cookies?.sessionId || null
  };

  res.setHeader('X-Request-ID', req.securityContext.requestId);
  next();
}

app.use(enrichRequestContext);

// Check for brute force attacks
async function checkBruteForce(username, clientIP) {
  const userKey = `failed:user:${username}`;
  const ipKey = `failed:ip:${clientIP}`;

  const [userAttempts, ipAttempts] = await Promise.all([
    redis.get(userKey),
    redis.get(ipKey)
  ]);

  return {
    userLocked: parseInt(userAttempts || 0) >= THRESHOLDS.MAX_FAILED_ATTEMPTS_PER_USER,
    ipBlocked: parseInt(ipAttempts || 0) >= THRESHOLDS.MAX_FAILED_ATTEMPTS_PER_IP,
    userAttempts: parseInt(userAttempts || 0),
    ipAttempts: parseInt(ipAttempts || 0)
  };
}

// Record failed attempt
async function recordFailedAttempt(username, clientIP, ctx) {
  const userKey = `failed:user:${username}`;
  const ipKey = `failed:ip:${clientIP}`;

  const pipeline = redis.pipeline();
  pipeline.incr(userKey);
  pipeline.expire(userKey, THRESHOLDS.LOCKOUT_DURATION_SECONDS);
  pipeline.incr(ipKey);
  pipeline.expire(ipKey, THRESHOLDS.LOCKOUT_DURATION_SECONDS);
  const results = await pipeline.exec();

  const newUserAttempts = results[0][1];
  const newIPAttempts = results[2][1];

  // Detect brute force pattern
  if (newUserAttempts >= THRESHOLDS.MAX_FAILED_ATTEMPTS_PER_USER) {
    securityLogger.error({
      event: SecurityEvents.AUTH_BRUTE_FORCE_DETECTED,
      severity: 'HIGH',
      target: 'user',
      username: username,
      attemptCount: newUserAttempts,
      ...ctx,
      alertRequired: true
    });
  }

  if (newIPAttempts >= THRESHOLDS.MAX_FAILED_ATTEMPTS_PER_IP) {
    securityLogger.error({
      event: SecurityEvents.AUTH_BRUTE_FORCE_DETECTED,
      severity: 'CRITICAL',
      target: 'ip',
      attemptCount: newIPAttempts,
      ...ctx,
      alertRequired: true,
      recommendedAction: 'BLOCK_IP'
    });
  }
}

// Check for impossible travel
async function checkImpossibleTravel(userId, currentGeo, ctx) {
  const lastLoginKey = `lastlogin:${userId}`;
  const lastLogin = await redis.hgetall(lastLoginKey);

  if (lastLogin && lastLogin.latitude && currentGeo.latitude) {
    const timeDiffHours = (Date.now() - parseInt(lastLogin.timestamp)) / (1000 * 60 * 60);
    const distance = calculateDistance(
      parseFloat(lastLogin.latitude),
      parseFloat(lastLogin.longitude),
      currentGeo.latitude,
      currentGeo.longitude
    );

    const speedKmh = distance / timeDiffHours;

    if (speedKmh > THRESHOLDS.IMPOSSIBLE_TRAVEL_SPEED_KMH && timeDiffHours < 24) {
      securityLogger.error({
        event: SecurityEvents.AUTH_IMPOSSIBLE_TRAVEL,
        severity: 'CRITICAL',
        userId: userId,
        previousLocation: { lat: lastLogin.latitude, lon: lastLogin.longitude, country: lastLogin.country },
        currentLocation: { lat: currentGeo.latitude, lon: currentGeo.longitude, country: currentGeo.country },
        distanceKm: Math.round(distance),
        timeDiffHours: timeDiffHours.toFixed(2),
        impliedSpeedKmh: Math.round(speedKmh),
        ...ctx,
        alertRequired: true,
        recommendedAction: 'REQUIRE_MFA'
      });
      return true;
    }
  }
  return false;
}

// Haversine formula for distance calculation
function calculateDistance(lat1, lon1, lat2, lon2) {
  const R = 6371; // Earth's radius in km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

// Update last login location
async function updateLastLogin(userId, geo) {
  const lastLoginKey = `lastlogin:${userId}`;
  await redis.hmset(lastLoginKey, {
    timestamp: Date.now().toString(),
    latitude: geo.latitude?.toString() || '',
    longitude: geo.longitude?.toString() || '',
    country: geo.country || '',
    city: geo.city || ''
  });
  await redis.expire(lastLoginKey, 30 * 24 * 60 * 60); // 30 days
}

// Clear failed attempts on success
async function clearFailedAttempts(username, clientIP) {
  await Promise.all([
    redis.del(`failed:user:${username}`),
    redis.del(`failed:ip:${clientIP}`)
  ]);
}

// Main login endpoint
app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;
  const ctx = req.securityContext;

  // Input validation
  if (!username || !password) {
    return res.status(400).json({ error: 'Missing credentials' });
  }

  try {
    // Check brute force protection
    const bruteForceStatus = await checkBruteForce(username, ctx.clientIP);

    if (bruteForceStatus.userLocked) {
      securityLogger.warn({
        event: SecurityEvents.AUTH_ACCOUNT_LOCKED,
        username: username,
        reason: 'excessive_failed_attempts',
        attemptCount: bruteForceStatus.userAttempts,
        ...ctx
      });
      return res.status(429).json({
        error: 'Account temporarily locked',
        retryAfter: THRESHOLDS.LOCKOUT_DURATION_SECONDS
      });
    }

    if (bruteForceStatus.ipBlocked) {
      securityLogger.warn({
        event: 'auth.ip.blocked',
        reason: 'excessive_failed_attempts_from_ip',
        attemptCount: bruteForceStatus.ipAttempts,
        ...ctx
      });
      return res.status(429).json({
        error: 'Too many requests',
        retryAfter: THRESHOLDS.LOCKOUT_DURATION_SECONDS
      });
    }

    // Find user
    const user = await db.findUserByUsername(username);

    if (!user) {
      securityLogger.warn({
        event: SecurityEvents.AUTH_LOGIN_FAILURE,
        username: username,
        failureReason: 'user_not_found',
        severity: 'MEDIUM',
        ...ctx
      });
      await recordFailedAttempt(username, ctx.clientIP, ctx);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Verify password
    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      securityLogger.warn({
        event: SecurityEvents.AUTH_LOGIN_FAILURE,
        userId: user.id,
        username: username,
        failureReason: 'invalid_password',
        severity: 'MEDIUM',
        ...ctx
      });
      await recordFailedAttempt(username, ctx.clientIP, ctx);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Check for impossible travel (anomaly detection)
    const isSuspicious = await checkImpossibleTravel(user.id, ctx, ctx);

    // Generate token
    const token = jwt.sign(
      {
        userId: user.id,
        sessionId: uuidv4()
      },
      process.env.JWT_SECRET,
      { expiresIn: '1h' }
    );

    // Log successful authentication
    securityLogger.info({
      event: SecurityEvents.AUTH_LOGIN_SUCCESS,
      userId: user.id,
      username: username,
      role: user.role,
      isPrivileged: user.role === 'admin',
      suspiciousIndicators: isSuspicious ? ['impossible_travel'] : [],
      ...ctx
    });

    // Log privileged access separately
    if (user.role === 'admin') {
      securityLogger.info({
        event: SecurityEvents.AUTH_PRIVILEGED_ACCESS,
        userId: user.id,
        username: username,
        privilegeLevel: user.role,
        severity: 'HIGH',
        ...ctx
      });
    }

    // Update tracking data
    await Promise.all([
      clearFailedAttempts(username, ctx.clientIP),
      updateLastLogin(user.id, ctx)
    ]);

    return res.json({
      token,
      requiresMFA: isSuspicious
    });

  } catch (error) {
    securityLogger.error({
      event: 'auth.error',
      error: error.message,
      stack: process.env.NODE_ENV === 'development' ? error.stack : undefined,
      severity: 'HIGH',
      ...ctx
    });
    return res.status(500).json({ error: 'Authentication service error' });
  }
});

module.exports = app;
